Mono\',monospace" font-size="2.5" fill="#2a2a2a" letter-spacing="0.2">ONEE. DOSE. DAILY.</text>\n            </g>\n\n            <!-- ══ BOTTLE 4 : DEEP DUSK (Spray Bottle) ══ -->\n            <g>\n              <!-- Spray actuator body -->\n              <path d="M 433,108 C 432,106 448,106 449,108 L 449,119 C 449,120 433,120 433,119 Z"\n                    stroke="#2a2a2a" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="#3a3a2a"/>\n              <!-- Actuator tube -->\n              <line x1="440" y1="106" x2="440" y2="95" stroke="#2a2a2a" stroke-width="2.5" stroke-linecap="round"/>\n              <!-- Nozzle tip -->\n              <path d="M 437,92 C 436,91 444,91 445,92 L 445,97 C 445,98 437,98 437,97 Z"\n                    stroke="#2a2a2a" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" fill="#3a3a2a"/>\n\n              <!-- Spray cap -->\n              <path d="M 422,119 C 421,117 459,117 460,119 L 461,140 C 461,142 421,142 421,140 Z"\n                    stroke="#2a2a2a" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="#3a3a2a"/>\n\n              <!-- Bottle body (flat bottom) -->\n              <path d="M 414,140 C 413,138 467,138 468,140\n                       L 469,333 C 470,339 466,342 461,342\n                       L 419,342 C 414,342 410,339 411,333 Z"\n                    stroke="#2a2a2a" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="#4a4a3a"/>\n\n              <!-- Brand (light text on dark) -->\n              <text x="448" y="160" font-family="Inter,sans-serif" font-size="5.5" font-weight="800" fill="#e8e5e0">ODD</text>\n              <text x="448" y="165.5" font-family="Inter,sans-serif" font-size="3.2" fill="#c8c5c0">care</text>\n              <text x="448" y="169.5" font-family="Inter,sans-serif" font-size="3.2" fill="#c8c5c0">co.</text>\n\n              <!-- Product name (vertical, light text) -->\n              <text x="445" y="160" transform="rotate(90,4